#include <string.h>

static inline int em_check_default_plc_creds(const char *payload) {
    if (payload == NULL) return 0;

    // Known default credential patterns for PLC platforms
    static const char *cred_patterns[] = {
        "username=openplc&password=openplc",
        "username=admin&password=admin",
        "username=admin&password=password",
        "username=admin&password=1234",
        "username=user&password=user",
        "user=openplc&pass=openplc",
        "user=admin&pass=admin",
        "login=admin&password=admin",
        "login=openplc&password=openplc"
    };
    static const int num_patterns = sizeof(cred_patterns) / sizeof(cred_patterns[0]);

    // Must be an HTTP POST request
    if (strncmp(payload, "POST", 4) != 0) return 0;

    // Must target a login endpoint
    if (strstr(payload, "/login") == NULL &&
        strstr(payload, "/authenticate") == NULL &&
        strstr(payload, "/api/login") == NULL) return 0;

    // Check for default credential patterns in the body
    int i;
    for (i = 0; i < num_patterns; i++) {
        if (strstr(payload, cred_patterns[i]) != NULL) {
            return 1;
        }
    }

    return 0;
}
